-- Schema de la base de datos 'goa'
-- Generado el: 2026-06-04
-- Con bloques temáticos numéricos (control interno)
-- Opciones numéricas, respuestas de texto completo y contenido sin prefijos de bloque

CREATE DATABASE IF NOT EXISTS `goa`;
USE `goa`;

--
-- Estructura de tabla para la tabla `profesores`
--
DROP TABLE IF EXISTS `resultados_estudiantes`;
DROP TABLE IF EXISTS `sesiones`;
DROP TABLE IF EXISTS `profesores`;
CREATE TABLE `profesores` (
  `id_profesor` int NOT NULL AUTO_INCREMENT,
  `nombre` varchar(100) DEFAULT NULL,
  `username` varchar(100) NOT NULL,
  `contrasena` varchar(100) NOT NULL,
  PRIMARY KEY (`id_profesor`),
  UNIQUE KEY `username` (`username`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

--
-- Estructura de tabla para la tabla `sesiones`
--
CREATE TABLE `sesiones` (
  `codigo_acceso` varchar(10) NOT NULL,
  `id_profesor` int DEFAULT NULL,
  PRIMARY KEY (`codigo_acceso`),
  KEY `id_profesor` (`id_profesor`),
  CONSTRAINT `sesiones_ibfk_1` FOREIGN KEY (`id_profesor`) REFERENCES `profesores` (`id_profesor`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

--
-- Estructura de tabla para la tabla `resultados_estudiantes`
--
CREATE TABLE `resultados_estudiantes` (
  `id_resultado` int NOT NULL AUTO_INCREMENT,
  `codigo_acceso` varchar(10) DEFAULT NULL,
  `nombre_alumno` varchar(100) DEFAULT NULL,
  `puntaje` int DEFAULT '0',
  `correctas` int DEFAULT '0',
  `incorrectas` int DEFAULT '0',
  PRIMARY KEY (`id_resultado`),
  KEY `codigo_acceso` (`codigo_acceso`),
  CONSTRAINT `resultados_estudiantes_ibfk_1` FOREIGN KEY (`codigo_acceso`) REFERENCES `sesiones` (`codigo_acceso`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

--
-- Estructura de tabla para la tabla `banco_preguntas`
--
DROP TABLE IF EXISTS `banco_preguntas`;
CREATE TABLE `banco_preguntas` (
  `bloque` int NOT NULL DEFAULT 1,
  `id_pregunta` int NOT NULL AUTO_INCREMENT,
  `pregunta` text NOT NULL,
  `opcion_1` varchar(255) DEFAULT NULL,
  `feedback_1` text DEFAULT NULL,
  `opcion_2` varchar(255) DEFAULT NULL,
  `feedback_2` text DEFAULT NULL,
  `opcion_3` varchar(255) DEFAULT NULL,
  `feedback_3` text DEFAULT NULL,
  `opcion_4` varchar(255) DEFAULT NULL,
  `feedback_4` text DEFAULT NULL,
  `respuesta_correcta` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id_pregunta`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

--
-- Volcado de datos para la tabla `banco_preguntas`
--
INSERT INTO `banco_preguntas` (`bloque`, `id_pregunta`, `pregunta`, `opcion_1`, `feedback_1`, `opcion_2`, `feedback_2`, `opcion_3`, `feedback_3`, `opcion_4`, `feedback_4`, `respuesta_correcta`) VALUES
(1, 1, '¿Cuál es el orden jerárquico correcto de la regla de las 3R para mejorar el manejo de residuos?', 'Rápido, Robusto, Real.', 'Incorrecta: Estos términos no describen procesos ambientales ni tienen relación con la gestión de residuos.', 'Recoger, Retener, Regalar.', 'Incorrecta: No representan el ciclo de economía circular ni la jerarquía de gestión.', 'Reducir, Reutilizar, Reciclar.', 'Correcta: Es el estándar internacional que prioriza evitar la basura antes de procesarla, siguiendo el orden de impacto.', 'Rotar, Repetir, Reparar.', 'Incorrecta: Aunque reparar es parte de la economía circular, no cubren la jerarquía completa del ciclo.', 'Reducir, Reutilizar, Reciclar.'),
(1, 2, 'Si notas que las canecas de reciclaje están mezcladas con restos de comida, ¿por qué esto impide el reciclaje?', 'Porque el plástico se pone pesado para los que recogen la basura.', 'Incorrecta: El peso no es el factor técnico que impide el proceso industrial.', 'Porque los restos orgánicos contaminan el material aprovechable, volviéndolo inservible para la industria.', 'Correcta: La contaminación cruzada destruye la pureza y el valor comercial del material reciclable.', 'Porque el plástico ya no se puede lavar en el colegio.', 'Incorrecta: El problema no es la limpieza, sino la mezcla en el origen que degrada el material.', 'Porque la caneca pierde el color que la identifica.', 'Incorrecta: El color es una guía visual para el usuario, pero no afecta la calidad del residuo.', 'Porque los restos orgánicos contaminan el material aprovechable, volviéndolo inservible para la industria.'),
(1, 3, 'Autocompleta: "Si compro un paquete de mecatos en el kiosko del colegio, la acción más responsable para evitar que el empaque termine en el suelo es..."', 'Tirarlo en la caneca, aunque esté llena, para que alguien más lo gestione después.', 'Incorrecta: Al estar llena, el residuo terminará dispersándose por el patio por acción del viento.', 'Dejar el paquete sobre la mesa para que el personal de aseo lo encuentre más fácil.', 'Incorrecta: Esto traslada una responsabilidad tuya y facilita que los residuos terminen en el piso.', 'Guardarlo en mi morral o bolsillo hasta encontrar una caneca con espacio o llegar a casa, asumiendo la responsabilidad del residuo desde que termina mi consumo.', 'Correcta: Esta acción garantiza el control total del residuo y evita la contaminación del entorno.', 'Arrugarlo y entregárselo a un compañero como broma.', 'Incorrecta: Genera desorden, distracción y no resuelve la disposición del residuo.', 'Guardarlo en mi morral o bolsillo hasta encontrar una caneca con espacio o llegar a casa, asumiendo la responsabilidad del residuo desde que termina mi consumo.'),
(1, 4, 'Si se organiza un evento en tu institución educativa, ¿qué decisión es más efectiva para prevenir la acumulación de basura?', 'Comprar botellas de agua individuales para todos.', 'Incorrecta: Esto genera una cantidad masiva de plástico desechable innecesario.', 'Solicitar que cada persona traiga su propio termo reutilizable, evitando el uso de envases de un solo uso.', 'Correcta: La prevención de la generación de basura es la forma más efectiva de gestión ambiental.', 'Contratar a más personas para que recojan la basura.', 'Incorrecta: Esto mitiga el impacto visual, pero no reduce la cantidad de residuos generados.', 'Comprar únicamente desechables que digan "biodegradable".', 'Incorrecta: Los biodegradables requieren condiciones de compostaje industrial que no están presentes en el colegio.', 'Solicitar que cada persona traiga su propio termo reutilizable, evitando el uso de envases de un solo uso.'),
(1, 5, 'En tu casa, ¿por qué es importante separar los restos de comida de los plásticos y papeles?', 'Porque el plástico pierde su color original si toca restos de comida.', 'Incorrecta: El color no es la razón técnica del reciclaje.', 'Porque lo orgánico contamina el material seco, impidiendo que sea procesado como reciclaje.', 'Correcta: La presencia de materia orgánica degrada la calidad de los materiales aprovechables.', 'Porque el plástico se vuelve más ligero si está sucio.', 'Incorrecta: La suciedad orgánica aumenta el peso y contamina el proceso.', 'Porque es más fácil llenar las bolsas así.', 'Incorrecta: El objetivo no es llenar bolsas, sino gestionar los residuos eficientemente.', 'Porque lo orgánico contamina el material seco, impidiendo que sea procesado como reciclaje.'),
(2, 6, '¿Por qué es crítico evitar que el aceite de cocina usado se vierta por el lavaplatos?', 'Porque el aceite huele mal y atrae insectos.', 'Incorrecta: El impacto ambiental es mucho más grave que un tema de higiene menor.', 'Porque el aceite crea capas impermeables que contaminan el agua y dañan el ecosistema marino.', 'Correcta: El aceite es un contaminante mayor que impide la oxigenación de nuestra bahía.', 'Porque el aceite hace que la tubería se caliente demasiado.', 'Incorrecta: El aceite no tiene propiedades para elevar la temperatura de la tubería.', 'Porque el aceite debe quemarse en casa.', 'Incorrecta: Quemar aceite libera gases tóxicos.', 'Porque el aceite crea capas impermeables que contaminan el agua y dañan el ecosistema marino.'),
(2, 7, 'Autocompleta: "Si identifico una fuga de agua en los baños de mi institución educativa, lo más responsable es..."', 'Ignorarla, porque no es mi trabajo arreglarla.', 'Incorrecta: Ignorar el problema permite el desperdicio continuo.', 'Intentar cerrarla con fuerza, aunque siga goteando.', 'Incorrecta: No soluciona el problema de fondo.', 'Avisar inmediatamente a un docente o al personal de mantenimiento del colegio para su reparación.', 'Correcta: Lideras la solución al desperdicio del recurso.', 'Dejar que el agua siga corriendo para que no se seque el piso.', 'Incorrecta: Es un desperdicio injustificado de un recurso limitado.', 'Avisar inmediatamente a un docente o al personal de mantenimiento del colegio para su reparación.'),
(2, 8, 'Clasifica: En tu institución educativa, hay una caneca de color gris destinada a residuos peligrosos. De los siguientes elementos, ¿cuál es un residuo peligroso que nunca debe ir al alcantarillado y que sería bueno colocar en esta caneca?', 'Restos de cáscaras de banano o mango.', 'Incorrecta: Son materia orgánica que debería ir en la caneca de orgánicos/verde.', 'Envases de plástico vacíos y limpios que usamos en el descanso.', 'Incorrecta: Estos deben ir en la caneca de aprovechables/azul.', 'Hojas de papel de cuadernos viejos que ya no usamos.', 'Incorrecta: El papel debe ir en la caneca blanca.', 'Pilas, baterías usadas de los controles o medicamentos vencidos.', 'Correcta: Son residuos peligrosos que contienen metales pesados que envenenan el agua si terminan en el alcantarillado.', 'Pilas, baterías usadas de los controles o medicamentos vencidos.'),
(2, 9, 'Cuando tiramos basura en la carretera frente a nuestra institución educativa, ¿qué sucede en esa zona cuando llega la época de lluvia y la bajada se inunda?', 'La corriente de agua limpia la carretera y lleva la basura a un lugar seguro.', 'Incorrecta: El agua de lluvia no limpia, sino que arrastra los residuos hacia los sumideros.', 'La basura obstruye los desagües y alcantarillas, provocando que el agua se estanque y se inunde la bajada de nuestro colegio.', 'Correcta: Al taponar la red de drenaje, el agua no tiene por dónde circular, causando inundaciones que afectan el acceso al colegio.', 'La basura se hunde y desaparece bajo el agua sin causar ningún problema.', 'Incorrecta: Los residuos sólidos obstruyen el flujo y permanecen ahí.', 'La basura ayuda a que el agua circule más rápido por la carretera.', 'Incorrecta: Los residuos actúan como barreras que impiden el flujo normal.', 'La basura obstruye los desagües y alcantarillas, provocando que el agua se estanque y se inunde la bajada de nuestro colegio.'),
(2, 10, 'Ordena: ¿Cuál es la secuencia lógica que maximiza el impacto pedagógico y la solución técnica si ves a alguien desperdiciando agua en el colegio? Pasos:\n1. Evaluar si la llave tiene una falla mecánica (fuga) o si es un mal uso del compañero.\n2. Iniciar una conversación empática enfocada en el impacto ambiental del desperdicio.\n3. Invitar al compañero a corregir la acción y comprometerse con el cuidado del agua.\n4. Informar a las autoridades del colegio para que realicen el mantenimiento preventivo o correctivo necesario.', '4-3-2-1', 'Incorrecta: Reportar sin dialogar ignora la oportunidad pedagógica.', '3-2-4-1', 'Incorrecta: La invitación a corregir debe ser el resultado del diálogo.', '2-3-1-4', 'Correcta: Comienza con empatía, sigue con la corrección del hábito, la verificación técnica y la solución institucional.', '1-2-4-3', 'Incorrecta: Reportar la falla antes de dialogar omite el proceso pedagógico básico.', '2-3-1-4'),
(3, 11, '¿Qué es la "huella ecológica" y cómo se relaciona con nuestras decisiones diarias en el colegio?', 'La cantidad de basura que genera un estudiante.', 'Incorrecta: Ese es solo un componente menor.', 'La medida del impacto ambiental total que generan nuestras actividades y consumo de recursos.', 'Correcta: Aplica la Nota 1; mide cuánta naturaleza necesitamos para mantener nuestro estilo de vida.', 'El rastro que dejan los estudiantes al caminar por el patio.', 'Incorrecta: Es un término ambiental, no físico.', 'La técnica para limpiar el colegio después del descanso.', 'Incorrecta: Eso es una acción de mantenimiento, no una medición.', 'La medida del impacto ambiental total que generan nuestras actividades y consumo de recursos.'),
(3, 12, 'Autocompleta: "Si al salir del salón de clases noto que los ventiladores y luces quedan encendidos, lo más responsable es..."', 'Dejarlos encendidos porque el profesor los apagará después.', 'Incorrecta: El ahorro es una responsabilidad colectiva.', 'Pedirle a un compañero que los apague por mí.', 'Incorrecta: Debes tomar la iniciativa tú mismo.', 'Apagarlos inmediatamente para reducir el consumo energético innecesario.', 'Correcta: Aplica la Nota 2; menos demanda significa un menor impacto ambiental.', 'Entrar a otro salón a jugar mientras espero que alguien los apague.', 'Incorrecta: No aborda el problema del desperdicio.', 'Apagarlos inmediatamente para reducir el consumo energético innecesario.'),
(3, 13, 'Elige: En la tienda del colegio, hay varias opciones para comprar una bebida. De los siguientes elementos, ¿cuál representa un consumo más responsable?', 'Una botella plástica de agua de un solo uso.', 'Incorrecta: Genera un residuo innecesario que impacta el alcantarillado.', 'Una bebida en lata que viene en un paquete de seis unidades.', 'Incorrecta: Aunque el aluminio es reciclable, el empaque genera residuos extra.', 'Llevar tu propio termo reutilizable y llenarlo en los puntos de hidratación.', 'Correcta: Aplicas la Nota 3; evitas generar un residuo desde la fuente.', 'Comprar jugos en cajas pequeñas con pitillos plásticos.', 'Incorrecta: El uso combinado de papel, plástico y pitillo dificulta su gestión.', 'Llevar tu propio termo reutilizable y llenarlo en los puntos de hidratación.'),
(3, 14, '¿Cómo ayuda el uso de transporte compartido o caminar para llegar al colegio?', 'Solo sirve para ahorrar dinero en pasajes.', 'Incorrecta: Ese es un beneficio personal, pero no ambiental.', 'Reduce la cantidad de vehículos individuales y sus emisiones de CO2 al ambiente.', 'Correcta: Aplica la Nota 2; menos vehículos circulando significan una menor huella invisible.', 'Es más rápido que ir en bicicleta.', 'Incorrecta: No siempre es cierto en una ciudad como Cartagena.', 'Es una norma que exige el colegio para todos.', 'Incorrecta: Es una elección personal con impacto colectivo.', 'Reduce la cantidad de vehículos individuales y sus emisiones de CO2 al ambiente.'),
(3, 15, 'Ordena: ¿Cuál es la secuencia lógica para aplicar el consumo responsable al comprar materiales para una tarea escolar? Pasos:\n1. Verificar si tengo materiales reutilizables en casa.\n2. Comparar productos buscando los que tengan menos empaque.\n3. Evaluar si la marca tiene prácticas ambientales responsables.\n4. Comprar solo lo estrictamente necesario.', '4-3-2-1', 'Incorrecta: Debes verificar lo que ya tienes antes de comprar.', '3-2-1-4', 'Incorrecta: El orden no sigue la jerarquía de sostenibilidad.', '1-4-2-3', 'Correcta: Primero reutilizas, luego compras lo justo, priorizando empaques y marcas responsables.', '2-1-3-4', 'Incorrecta: No es eficiente evaluar marcas antes de saber qué necesitas.', '1-4-2-3'),
(4, 16, '¿Cuál es la forma más efectiva de motivar a otros a cuidar el medio ambiente en el colegio?', 'Poner carteles de "Prohibido ensuciar" por todos lados.', 'Incorrecta: Los letreros suelen ser ignorados rápidamente.', 'Liderar con el ejemplo y explicar los beneficios colectivos de mantener el espacio limpio.', 'Correcta: La coherencia y la pedagogía inspiran a los demás.', 'Reportar a todos los que ensucien ante las directivas para que los sancionen.', 'Incorrecta: El miedo no genera conciencia a largo plazo.', 'Dejar de hablarles a quienes no cuidan el entorno.', 'Incorrecta: El aislamiento no construye comunidad.', 'Liderar con el ejemplo y explicar los beneficios colectivos de mantener el espacio limpio.'),
(4, 17, 'Autocompleta: "Un verdadero líder ambiental en el colegio es aquel que..."', 'Siempre le dice a los demás qué hacer.', 'Incorrecta: El liderazgo no es dar órdenes.', 'Se encarga de limpiar todo lo que otros ensucian.', 'Incorrecta: Eso soluciona el residuo, pero no el comportamiento.', 'Motiva a sus compañeros a transformar sus hábitos mediante el diálogo y la acción constante.', 'Correcta: El liderazgo ambiental implica inspirar cambios sostenibles.', 'Solo participa si le dan una nota extra en clase.', 'Incorrecta: El compromiso ambiental nace de la convicción personal.', 'Motiva a sus compañeros a transformar sus hábitos mediante el diálogo y la acción constante.'),
(4, 18, 'Elige: Si quieres organizar una jornada de recuperación de un espacio con maleza, ¿cuál es el primer paso lógico que debes dar?', 'Ir y empezar a limpiar solo con un machete.', 'Incorrecta: Es un gesto heroico, pero no genera un impacto comunitario ni es seguro.', 'Pedirle a un docente que te ayude a convocar a otros compañeros interesados y coordinar el apoyo necesario.', 'Correcta: La organización y el trabajo en equipo son la base de las acciones comunitarias.', 'Comprar herramientas para todos con tu propio dinero.', 'Incorrecta: Es un gasto innecesario antes de tener un equipo estructurado.', 'Publicar fotos en redes sociales diciendo que el espacio está abandonado.', 'Incorrecta: Eso es quejarse, no liderar un cambio.', 'Pedirle a un docente que te ayude a convocar a otros compañeros interesados y coordinar el apoyo necesario.'),
(4, 19, '¿Por qué es importante involucrar a otros miembros de la comunidad escolar cuando haces una actividad ambiental?', 'Porque así el colegio se ve mejor ante las autoridades.', 'Incorrecta: El objetivo debe ser el impacto ambiental real, no la apariencia.', 'Porque el entorno es compartido y el cambio de hábitos es más duradero si todos participan.', 'Correcta: La acción colectiva asegura que el entorno se mantenga cuidado a largo plazo.', 'Porque si no, la gente se va a quejar de que hacemos ruido.', 'Incorrecta: La participación es para generar conciencia, no solo por evitar quejas.', 'No es importante; solo los que iniciaron el proyecto deben trabajar.', 'Incorrecta: Los problemas ambientales requieren soluciones de toda la comunidad.', 'Porque el entorno es compartido y el cambio de hábitos es más duradero si todos participan.'),
(4, 20, 'Ordena: ¿Cuál es la secuencia lógica para consolidar un grupo de "Guardianes Ambientales" en tu colegio? Pasos:\n1. Identificar compañeros con intereses similares.\n2. Definir una meta pequeña y alcanzable (ej. recuperar un pequeño sector de la lomita).\n3. Presentar la propuesta a las directivas para obtener apoyo y seguridad.\n4. Celebrar los logros con todo el grupo para mantener la motivación.', '4-3-2-1', 'Incorrecta: No puedes celebrar antes de planear y actuar.', '3-2-1-4', 'Incorrecta: Debes tener el equipo antes de buscar apoyo oficial.', '1-2-3-4', 'Correcta: Primero creas el equipo, luego planeas, gestionas apoyo y finalmente fortaleces el grupo con logros.', '2-1-4-3', 'Incorrecta: Debes identificar el equipo antes de definir metas.', '1-2-3-4');

--
-- Estructura de tabla para la tabla `historia_interactiva`
--
DROP TABLE IF EXISTS `historia_interactiva`;
CREATE TABLE `historia_interactiva` (
  `bloque` int NOT NULL DEFAULT 1,
  `id_nodo` int NOT NULL AUTO_INCREMENT,
  `escena_titulo` varchar(100) DEFAULT NULL,
  `texto_situacion` text,
  `opcion_1` text,
  `feedback_1` text DEFAULT NULL,
  `opcion_2` text,
  `feedback_2` text DEFAULT NULL,
  `opcion_3` text,
  `feedback_3` text DEFAULT NULL,
  `respuesta_correcta` text,
  PRIMARY KEY (`id_nodo`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

--
-- Volcado de datos para la tabla `historia_interactiva`
--
INSERT INTO `historia_interactiva` (`bloque`, `id_nodo`, `escena_titulo`, `texto_situacion`, `opcion_1`, `feedback_1`, `opcion_2`, `feedback_2`, `opcion_3`, `feedback_3`, `respuesta_correcta`) VALUES
(1, 1, 'Nudo 1: El descarte tras el descanso', 'Estás en pleno descanso en el "Ana María Vélez". El kiosko está lleno de gente comiendo mecatos, y se ve un despelote de bolsas en el patio. Tú tienes una botella vacía y un paquete de mecatos en la mano.\n\nSuena el timbre para entrar a clase y el patio queda sucio. La brisa empieza a mover las bolsas de tus compañeros.', 'Dejar todo ahí en el piso porque "la señora del aseo lo recoge".', 'Incorrecto: El plástico demora siglos en descomponerse.', 'Tirar todo en la caneca, aunque esté rebosada.', 'Duda: Si la caneca está llena, el residuo terminará volando igual.', 'Guardar tus residuos en el morral y llevarlos a una caneca vacía o a casa.', 'Correcto: Te haces responsable de tus residuos desde la fuente.', 'Guardar tus residuos en el morral y llevarlos a una caneca vacía o a casa.'),
(1, 2, 'Nudo 2: El encuentro en la puerta', 'Sales del colegio y ves a unos pelaos de otro colegio tirando latas en el parque de al lado.', 'Seguir derecho y no decirles nada.', 'Incorrecto: El entorno es colectivo; ignorar el daño permite que continúe.', 'Gritarles desde lejos que sean más conscientes.', 'Duda: La confrontación suele cerrar puertas.', 'Acercarte y decirles: "Oigan, pelaos, ¿no creen que sería mejor ponerlas en la caneca? Así el parque se ve más bonito y cuidamos el espacio entre todos".', 'Correcto: Usas la pedagogía y la invitación a la convivencia para cambiar hábitos.', 'Acercarte y decirles: "Oigan, pelaos, ¿no creen que sería mejor ponerlas en la caneca? Así el parque se ve más bonito y cuidamos el espacio entre todos".'),
(1, 3, 'Nudo 3: La reflexión en casa', 'Le cuentas a tu mamá lo que viste en el "Ana María Vélez" y en el parque. Ella te pregunta qué vas a hacer.', 'Decirle que el colegio es un desastre y que no hay nada que hacer.', 'Incorrecto: Al no tomar postura, permites que la negligencia gane.', 'Decirle que tú reciclarás, pero que tus amigos de noveno son los que tienen la culpa.', 'Duda: Es un paso adelante, pero falta involucrar a la comunidad.', 'Proponerle empezar a reciclar en casa y hablar con tus compañeros para crear un grupo de "Guardianes" en el colegio.', 'Correcto: Lideras con el ejemplo y conviertes la acción individual en colectiva.', 'Proponerle empezar a reciclar en casa y hablar con tus compañeros para crear un grupo de "Guardianes" en el colegio.'),
(2, 4, 'Nudo 1: El goteo de la llave', 'Es un día de mucho calor en el "Ana María Vélez". Acabas de terminar educación física y vas al baño a lavarte la cara. Te das cuenta de que hay una llave abierta goteando constantemente. Luego, vas al kiosko por un refresco y ves a la señora lavando los utensilios de cocina.\n\nEl grifo del baño gotea y gotea. Estás apurado por volver al salón, pero sabes que cada gota cuenta para la sostenibilidad de la ciudad.', 'Ignorar el goteo; es poquita agua.', 'Incorrecto: Ignoras la Nota 3.', 'Cerrar la llave lo más fuerte que puedas y seguir tu camino.', 'Duda: El problema técnico sigue ahí.', 'Cerrar la llave y avisar a un profesor para que reporten la fuga.', 'Correcto: Lideras la solución definitiva.', 'Cerrar la llave y avisar a un profesor para que reporten la fuga.'),
(2, 5, 'Nudo 2: El momento en el kiosko', 'Mientras compras tu refresco, observas que la señora del kiosko está lavando una olla con grasa y está a punto de verterla por el drenaje.', 'No decir nada porque no quieres meterte en la vida ajena.', 'Incorrecto: Ignoras la Nota 2; el aceite daña el alcantarillado.', 'Decirle "Señora, eso tapa el tubo", sin explicarle más.', 'Duda: Intentas corregir, pero debes ser más claro.', 'Acercarte y decirle: "Doña, ¿sabía que si guarda ese aceite en un tarro evita que se tape el tubo y contaminemos el mar?".', 'Correcto: Aplicas la Nota 2; educas sobre el residuo peligroso.', 'Acercarte y decirle: "Doña, ¿sabía que si guarda ese aceite en un tarro evita que se tape el tubo y contaminemos el mar?".'),
(2, 6, 'Nudo 3: La reflexión en casa', 'Le cuentas a tu mamá lo que viste en el "Ana María Vélez" y en el parque. Ella te pregunta qué vas a hacer ahora que sabes tanto sobre el agua.', 'Decirle que el colegio es un desastre.', 'Incorrecto: Al no tomar postura, permites que la negligencia gane.', 'Decirle que tú ahorrarás agua, pero que los demás sigan igual.', 'Duda: Es un paso adelante, pero falta involucrar a la comunidad.', 'Proponerle empezar a ahorrar agua en casa y hablar con tus amigos para cuidar mejor los grifos del colegio.', 'Correcto: Lideras con el ejemplo y conviertes la acción en colectiva.', 'Proponerle empezar a ahorrar agua en casa y hablar con tus amigos para cuidar mejor los grifos del colegio.'),
(3, 7, 'Nudo 1: La elección de los materiales', 'Tienes una tarea urgente para el profe de artística y necesitas materiales específicos. Decides ir al Mercadito de Santa Rita para conseguirlos con el dinero justo que te dio tu mamá.\n\nEn el mercadito, encuentras un kit escolar que viene en una caja de plástico gigante, o puedes comprar los elementos sueltos.', 'Comprar el kit gigante porque se ve completo y profesional.', 'No: Ignoras la Nota 1; pagas por un empaque excesivo que terminará en la basura.', 'Comprar el kit pero buscar a alguien que quiera la caja para guardar cosas.', 'Duda: Es un gesto noble, pero sigues fomentando la producción de plástico innecesario.', 'Comprar solo los elementos sueltos que necesitas y llevar tu propia bolsa de tela.', 'Sí: Aplicas la Nota 1 y 3; reduces desperdicio desde la fuente.', 'Comprar solo los elementos sueltos que necesitas y llevar tu propia bolsa de tela.'),
(3, 8, 'Nudo 2: La nevera del mercadito', 'Mientras pagas los materiales, notas que la nevera de las bebidas está entreabierta y el motor suena forzado por el calor del mediodía.', 'Ignorarlo y pagar rápido para irte a hacer la tarea.', 'No: Ignoras la Nota 2; el consumo energético se dispara innecesariamente.', 'Comprar una bebida fría ahí mismo aunque tengas tu termo, porque hace mucho calor.', 'Duda: Te refrescas, pero fomentas el consumo de un producto empacado.', 'Cerrar suavemente la puerta de la nevera y decirle al vendedor con amabilidad: "Don, la puerta estaba un poquito abierta, así no se le escapa el frío y no se le daña el motor".', 'Sí: Aplicas la Nota 2; promueves la eficiencia energética de forma respetuosa y cercana.', 'Cerrar suavemente la puerta de la nevera y decirle al vendedor con amabilidad: "Don, la puerta estaba un poquito abierta, así no se le escapa el frío y no se le daña el motor".'),
(3, 9, 'Nudo 3: El impacto de tu compra', 'Al terminar la compra, te das cuenta de que elegiste una marca local que fabrica papel reciclado en vez de la marca comercial que viene envuelta en plástico.', 'Arrepentirte porque la otra marca era más barata aunque el empaque fuera peor.', 'No: Ignoras la Nota 1; el ahorro inmediato no compensa el costo ambiental.', 'Pensar que por una sola persona no hace la diferencia.', 'Duda: El cambio individual es la base del cambio colectivo.', 'Sentirte bien porque sabes que tu compra apoya un mercado más responsable y reduce tu huella invisible.', 'Sí: Aplicas la Nota 3; tu dinero es un voto ambiental.', 'Sentirte bien porque sabes que tu compra apoya un mercado más responsable y reduce tu huella invisible.'),
(4, 10, 'Nudo 1: La primera reunión', 'Subiendo las escaleras del colegio, hay una lomita que solía ser bonita, pero ahora está llena de monte, maleza y la gente la usa para tirar basura. Un grupo de amigos decide que ya es hora de recuperarla.\n\nEl grupo está desanimado porque dicen que "la gente siempre volverá a tirar basura ahí".', 'Decirles que tienen razón y mejor olvidarse del proyecto.', 'No: Ignoras la Nota 1; tu actitud debe ser inspiradora.', 'Ponerte a limpiar tú solo para demostrarles que sí se puede.', 'Duda: Te agotas rápido y no creas un equipo de trabajo.', 'Proponerles que, además de limpiar, pongan un aviso creativo que explique por qué la lomita es importante para el aire del colegio.', 'Sí: Aplicas la Nota 2; educas para cambiar el hábito de raíz.', 'Proponerles que, además de limpiar, pongan un aviso creativo que explique por qué la lomita es importante para el aire del colegio.'),
(4, 11, 'Nudo 2: El reto del monte', 'Al empezar a limpiar, te das cuenta de que el monte está muy crecido y hay vidrios entre la maleza. Es peligroso.', 'Seguir limpiando a toda costa porque ya empezaron.', 'No: Es un riesgo innecesario; falta gestión.', 'Ignorar los vidrios y seguir adelante.', 'Duda: Puedes accidentar a tus compañeros.', 'Detener la jornada y hablar con un profesor para pedir apoyo de mantenimiento o herramientas adecuadas para limpiar de forma segura.', 'Sí: Aplicas la Nota 3; liderar es saber cuándo pedir ayuda para garantizar el éxito.', 'Detener la jornada y hablar con un profesor para pedir apoyo de mantenimiento o herramientas adecuadas para limpiar de forma segura.'),
(4, 12, 'Nudo 3: El impacto logrado', 'Después de semanas, la lomita luce limpia y empezaron a crecer plantas de nuevo. Pero un estudiante intenta tirar un envase ahí otra vez.', 'Gritarles para que se sienta mal y no lo vuelva a hacer.', 'No: Ignoras la Nota 2; la gente no cambia con regaños.', 'No decirle nada para evitar peleas.', 'Duda: Dejas que el trabajo se pierda.', 'Acercarte amablemente y decirle: "¡Hey, compañero! Estamos recuperando este espacio para que se vea bien el colegio, ¿nos ayudas a mantenerlo?".', 'Sí: Aplicas la Nota 1 y 2; tu liderazgo es contagioso y pedagógico.', 'Acercarte amablemente y decirle: "¡Hey, compañero! Estamos recuperando este espacio para que se vea bien el colegio, ¿nos ayudas a mantenerlo?".');

--
-- Estructura de tabla para la tabla `material_estudio`
--
DROP TABLE IF EXISTS `material_estudio`;
CREATE TABLE `material_estudio` (
  `bloque` int NOT NULL DEFAULT 1,
  `id_material` int NOT NULL AUTO_INCREMENT,
  `contenido` text,
  PRIMARY KEY (`id_material`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

--
-- Volcado de datos para la tabla `material_estudio`
--
INSERT INTO `material_estudio` (`bloque`, `id_material`, `contenido`) VALUES
(1, 1, 'GESTIÓN DE RESIDUOS Y RECICLAJE\n\nI. Kit del Guardián\n\nNota 1 (La jerarquía de la materia): No todo tiene el mismo \"tiempo de vida\". Lo orgánico vuelve a\nla tierra, pero lo artificial es eterno. Si los mezclas, anulas el valor de ambos.\n\nNota 2 (Principio de la Fuente): La separación debe hacerse donde el residuo nace (en tu mano).\nSeparar después de que todo está mezclado es una pérdida de energía.\n\nNota 3 (Regla de la \'No-Generación\'): Un objeto se convierte en \"basura\" solo cuando tú lo decides.\nSi evitas comprar un empaque innecesario, ahorras al sistema el costo de procesarlo.'),
(2, 2, 'CUIDADO DEL AGUA Y ALCANTARILLADO\n\nI. Kit del Guardián\n\nNota 1 (La interconexión urbana): En Cartagena, todo sistema de alcantarillado es un ciclo. Lo que tiras por el lavaplatos viaja hasta nuestras plantas de tratamiento o, peor aún, a nuestros canales y bahía.\n\nNota 2 (Densidad y Residuos Peligrosos): Algunos residuos, como el aceite o los químicos, crean capas impermeables que impiden que el agua se oxigene, matando la vida marina como peces y corales.\n\nNota 3 (El valor del recurso): El agua potable es limitada. Cada gota desperdiciada en casa o en el colegio es una gota menos para la sostenibilidad de nuestra ciudad'),
(3, 3, 'CONSUMO RESPONSABLE Y ENERGÍA\n\nI. Kit del Guardián\n\nNota 1 (La huella invisible): Todo lo que consumes tiene un costo energético oculto (transporte, empaque, refrigeración). Un producto que parece \"barato\" a menudo sale muy caro para el planeta.\n\nNota 2 (La eficiencia del uso): La energía más limpia y barata es la que no se consume. Apagar lo que no usas o elegir productos que duran más es la forma más directa de reducir tu huella.\n\nNota 3 (El poder de decisión): Tú eres el cliente. Si eliges comprar productos con menos empaque o marcas locales, obligas al mercado a ser más responsable. ¡Tu dinero es un voto ambiental!'),
(4, 4, 'LIDERAZGO Y COMUNIDAD AMBIENTAL\n\nI. Kit del Guardián\n\nNota 1 (Efecto Multiplicador): Un solo guardián ambiental no cambia el mundo, pero inspira a diez más. Tu actitud es contagiosa.\n\nNota 2 (El poder de la comunicación): No se trata de regañar, sino de invitar. La gente cambia cuando entiende el \"porqué\" de las cosas, no cuando se siente atacada.\n\nNota 3 (Acción Local, Impacto Global): Resolver el problema en tu colegio o barrio es la base para mejorar los ecosistemas urbanos de Cartagena.');
